## -- FUNÇÃO DE AVALIAÇÃO DO LLM -- ##
def llm_output(y_test, y_pred):
  print("-------- MODELO LLM --------")
  print("Accuracy:", accuracy_score(y_test, y_pred))
  print("\nRelatório de classificação:")
  print(classification_report(y_test, y_pred, labels = [-1, 0, 1], target_names = ['Citação (-1)', 'Facto (0)', 'Viés (1)']))
  print()

  # MATRIZ DE CONFUSÃO
  cm = confusion_matrix(y_test, y_pred)
  disp = ConfusionMatrixDisplay(confusion_matrix = cm, display_labels = [-1, 0, 1])
  disp.plot(cmap = plt.cm.Blues, values_format = 'd', text_kw = {'fontsize':16})
  plt.title("Matriz de Confusão", fontsize = 22)
  plt.xlabel("Classe Prevista", fontsize = 14)
  plt.ylabel("Classe Verdadeira", fontsize = 14)
  plt.show()


## -- LLM (CHAIN-OF-THOUGHTS PROMPTING) -- ##
df = pd.read_csv("frases_representativas.csv", on_bad_lines = 'skip')

def llm_model_fewshot(X_test, y_test):
    # Definir LLM
    llm = OllamaLLM(model = "llama3.2:3b", temperature = 0.1)

    # Prompt
    prompt = (
    """Classifique a frase em uma das três categorias:
        CITAÇÃO (c)
        FACTO (f)
        VIÉS (v)

        REGRAS:
        - CITAÇÃO (c): A frase relata algo que alguém disse, afirmou, declarou ou escreveu.
        - FACTO (f): Informação objetiva, verificável, sem opinião.
        - VIÉS (v): Opinião, julgamento, interpretação, emoção ou linguagem subjetiva.

        Agora classifica esta frase (como c, v ou f) e Retorna *APENAS* JSON no formato {"classe": ?, "raciocinio": "..."}: """
  )

    # --- Loop Principal --- #
    for i in range (len(X_test)):

        frase = X_test.iloc[i]
        tries = []
        promptfinal = prompt + frase

        # 3 tentativas para majority voting
        for _ in range(3):
            try:
                resposta = llm.invoke(promptfinal).strip()
                print("\n------------------")
                print(resposta)
            except:
                resposta = "0" # Caso dê erro, atribui 0 (classe maioritária)

            if '"c"' in resposta:
                resposta = "-1"
            elif '"v"' in resposta:
                resposta = "1"
            elif '"f"' in resposta:
                resposta = "0"
            else:
                print("NÃO RESPONDEU COM 1 0 -1")
                resposta = resposta # Mantém a resposta original para validação abaixo

            tries.append(resposta)

        final = Counter(tries).most_common(1)[0][0]
        y_pred.append(int(final))

        print(f"{i}/{len(X_test)} | {tries} → {final} | Real = {y_test.iloc[i]}")

    print("Terminado.")

    return y_pred


y_pred = llm_model_fewshot(X_test_filtered, y_test_filtered)
llm_output(y_test_filtered, y_pred)
